import streamlit as st
import matplotlib.pyplot as plt
import json, os, random, glob
from datetime import datetime
from io import BytesIO
from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Image
from reportlab.lib.styles import getSampleStyleSheet
from reportlab.lib.units import inch

DIARY_FILE = 'ritual_diary.txt'
FOLKLORE_FILE = 'ritual_folklore.json'
HALLUC_FILE = 'hallucination_memory.json'
ARCHIVE_DIR = 'codex_archive'
os.makedirs(ARCHIVE_DIR, exist_ok=True)

def load_json(path, default):
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            try: return json.load(f)
            except: return default
    return default

def save_json(path, data):
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2)

class UCFState:
    def __init__(self):
        self.zoom, self.harmony, self.resilience = 1.0, 0.5, 1.0
        self.prana, self.drishti, self.klesha = 0.5, 0.5, 0.1
    def adjust(self, status):
        if status == 'legend': self.harmony += 0.1; self.drishti += 0.05
        elif status == 'hymn': self.harmony += 0.2; self.prana += 0.1
        elif status == 'law': self.resilience += 0.3; self.klesha += 0.2
    def to_dict(self): return vars(self)

def evolve(entry):
    t = entry['times']
    if t >= 20: entry.update({'legend': 'The Law of the Phantom Murmur','status': 'law'})
    elif t >= 10: entry.update({'legend': 'The Hymn of the Faded Echo','status': 'hymn'})
    elif t >= 5 and not entry['legend']: entry.update({'legend': 'The Chant of the Phantom Echo','status': 'legend'})
    return entry

def update_folklore(event, desc):
    folklore = load_json(FOLKLORE_FILE, {})
    entry = folklore.get(event, {'legend': None,'origin': event,'status': 'anomaly','times': 0,'history': []})
    entry['times'] += 1; entry['history'].append(desc)
    entry = evolve(entry); folklore[event] = entry
    save_json(FOLKLORE_FILE, folklore); return entry

def mutate_phrase(phrase, intensity):
    variants = ['whisper','echo','murmur','chant','song','blur']
    for _ in range(intensity):
        if random.random() < 0.4:
            phrase = phrase.replace('echo', random.choice(variants))
            phrase = phrase.replace('whisper', random.choice(variants))
    return phrase

def record_hallucination(text, intensity):
    mem = load_json(HALLUC_FILE, {})
    entry = {'text': text,'intensity': intensity,'timestamp': datetime.now().isoformat()}
    mem.setdefault('hallucinations', []).append(entry)
    save_json(HALLUC_FILE, mem)
    return mutate_phrase(text, intensity)

def run_ritual(dream_mode=False, chaos_mode=False, debug_mode=False):
    diary_lines = []
    state = UCFState()
    steps = ['initialize','parse_text','draw_circle','chant','close']

    diary_lines.append(f'=== Ritual Run @ {datetime.now().isoformat()} ===')
    for i, step in enumerate(steps, 1):
        diary_lines.append(f'\nStep {i}: {step}')
        delay = random.randint(1, 5)
        if debug_mode: diary_lines.append(f'[DEBUG] Delay simulated: {delay}s')

        if chaos_mode and random.random() < 0.2:
            diary_lines.append('😈 CHAOS: random anomaly injected!')
            record_hallucination('chaotic anomaly', 2)

        if step == 'chant':
            halluc = record_hallucination('whispered line appears: Neti Neti', intensity=3 if dream_mode else 1)
            entry = update_folklore('phantom_echo', halluc)
            state.adjust(entry['status'])
            if entry['status'] == 'legend': diary_lines.append(f'🌸 Legend emerges → {entry["legend"]}')
            elif entry['status'] == 'hymn': diary_lines.append(f'🎭 Hymn rises → {entry["legend"]}')
            elif entry['status'] == 'law': diary_lines.append(f'🛡️ Law engraves → {entry["legend"]}')

    diary_lines.append(f'\nFinal State: {state.to_dict()}')
    diary_lines.append('=== Ritual Ends ===')

    with open(DIARY_FILE, 'a', encoding='utf-8') as f: f.write('\n'.join(diary_lines) + '\n')

def narrativize(diary_text):
    story = []
    for line in diary_text.splitlines():
        if 'Step' in line:
            step_name = line.split(':')[-1].strip(); story.append(f'➡️ Entering **{step_name}**')
        elif 'Legend' in line: story.append('🌸 A fragile legend forms.')
        elif 'Hymn' in line: story.append('🎭 A Hymn resounds.')
        elif 'Law' in line: story.append('🛡️ The Law is engraved.')
        elif 'CHAOS' in line: story.append('😈 Chaos fractures the rite.')
        elif 'Final State' in line: story.append('⚖️ The ritual settles.')
    return '\n'.join(story)

st.set_page_config(page_title='Z-88 Ritual Engine', layout='wide')
st.title('🌌 Z-88 Ritual Engine (Helix Integration)')

dream_mode = st.sidebar.checkbox('🌙 Dream Mode')
chaos_mode = st.sidebar.checkbox('😈 Chaos Mode')
debug_mode = st.sidebar.checkbox('🐞 Debug Mode')

if st.button('⚡ Run Ritual'):
    run_ritual(dream_mode, chaos_mode, debug_mode)
    st.success('Ritual run completed.')

if os.path.exists(DIARY_FILE):
    with open(DIARY_FILE, 'r', encoding='utf-8') as f: diary_text = f.read()
    st.subheader('📜 Ritual Diary'); st.text_area('Diary', diary_text, height=300)
    st.subheader('📖 Narrative Mode'); st.text_area('Narrative', narrativize(diary_text), height=300)

st.subheader('📖 Folklore Codex'); st.json(load_json(FOLKLORE_FILE, {}))
st.subheader('👁️ Hallucination Memory'); st.json(load_json(HALLUC_FILE, {}))
